import React from 'react';
import {
  LIN_ERP_LIST_FILTER_LAYOUT,
  LinPageLayout,
  type LinListToolbarActionDef,
} from '@linm-soft-org/linm-web-common-components';
import type { UseVoucherListSelectionResult } from '../../hooks/useVoucherListSelection';
import { WmsSchemaListGrid } from './WmsSchemaListGrid';
import erp from '../../styles/erpPage.module.css';

export type WmsInlineCreateListShellProps<T extends { id: string }> = {
  testIdPrefix: string;
  pageId: string;
  title: string;
  titleIconClass: string;
  listSubtitle: string;
  catalogKind: string;
  emptyLabel: string;
  items: T[];
  page: number;
  pageSize: number;
  showTableLoading: boolean;
  selection: UseVoucherListSelectionResult<T>;
  toolbarActions: LinListToolbarActionDef[];
  filters: React.ReactNode;
  footer: React.ReactNode;
  modals?: React.ReactNode;
  createPanel?: React.ReactNode | null;
  listRowMenuHelp?: boolean;
  viewMobile?: boolean;
  onRowOpenActionMenu?: (payload: { row: T; x: number; y: number }) => void;
};

/** Inline-create WMS list — schema grid + `toolbarProps` (Zone F config in overflow). */
export function WmsInlineCreateListShell<T extends { id: string }>({
  testIdPrefix,
  pageId,
  title,
  titleIconClass,
  listSubtitle,
  catalogKind,
  emptyLabel,
  items,
  page,
  pageSize,
  showTableLoading,
  selection,
  toolbarActions,
  filters,
  footer,
  modals,
  createPanel,
  listRowMenuHelp,
  viewMobile,
  onRowOpenActionMenu,
}: WmsInlineCreateListShellProps<T>): React.ReactElement {
  const toolbarProps = {
    testIdPrefix,
    profile: 'voucher' as const,
    actions: toolbarActions,
  };

  return (
    <div className={erp.voucherListRoot} data-voucher-list-page data-testid={`${testIdPrefix}-list`}>
      <LinPageLayout
        kind="voucher"
        testIdPrefix={testIdPrefix}
        pageId={pageId}
        pageClassName={`${erp.catalogListPage} ${erp.voucherListPage}`}
        header={{ title, titleIconClass, pageId }}
        toolbarProps={toolbarProps}
        listTitle={listSubtitle}
        listRowMenuHelp={listRowMenuHelp}
        filters={filters}
        listLayoutVariant="erp-filter-bar"
        listHeaderClassName={LIN_ERP_LIST_FILTER_LAYOUT.header}
        listFiltersClassName={LIN_ERP_LIST_FILTER_LAYOUT.filtersHost}
        showTableLoading={showTableLoading}
        skeletonRows={6}
        footer={footer}
        modals={modals}
      >
        {createPanel}
        <WmsSchemaListGrid
          catalogKind={catalogKind}
          testIdPrefix={testIdPrefix}
          rows={items}
          page={page}
          pageSize={pageSize}
          showTableLoading={showTableLoading}
          viewMobile={viewMobile}
          emptyLabel={emptyLabel}
          selection={selection}
          onRowOpenActionMenu={onRowOpenActionMenu}
        />
      </LinPageLayout>
    </div>
  );
}
